26	// CreatePod 创建 Pod
27	func (h *Handler) CreatePod(c *gin.Context) {
28		var req devmachinemodel.CreatePodRequest
29		if err := c.ShouldBindJSON(&req); err != nil {
30			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
31			return
32		}
33	
34		podSpec := &k8s.PodSpec{
35			Name:    req.Name,
36			Image:   req.Image,
37			Command: req.Command,
38			Args:    req.Args,
39			Env:     req.Env,
40			Labels:  req.Labels,
41		}
42	
43		if req.Resources != nil {
44			podSpec.Resources = &k8s.ResourceRequirements{
45				CPURequest:    req.Resources.CPURequest,
46				CPULimit:      req.Resources.CPULimit,
47				MemoryRequest: req.Resources.MemoryRequest,
48				MemoryLimit:   req.Resources.MemoryLimit,
49			}
50		}
51	
52		if err := h.service.CreatePod(c.Request.Context(), podSpec); err != nil {
53			h.logger.Error("failed to create pod", zap.Error(err), zap.String("name", req.Name))
54			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
55			return
56		}
57	
58		c.JSON(http.StatusOK, devmachinemodel.CreatePodResponse{Message: "pod created successfully"})
59	}
