10	// Service 开发机服务接口
11	type Service interface {
12		CreatePod(ctx context.Context, pod *k8s.PodSpec) error
13		DeletePod(ctx context.Context, name string) error
14		GetPod(ctx context.Context, name string) (*k8s.PodInfo, error)
15		ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error)
16		GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)
17	}
18	
19	type service struct {
20		k8sClient k8s.Client
21	}
22	
23	// NewService 创建开发机服务
24	func NewService(k8sClient k8s.Client) Service {
25		return &service{
26			k8sClient: k8sClient,
27		}
28	}
29	
30	func (s *service) CreatePod(ctx context.Context, pod *k8s.PodSpec) error {
31		if pod.Name == "" {
32			return fmt.Errorf("pod name cannot be empty")
33		}
34		if pod.Image == "" {
35			return fmt.Errorf("pod image cannot be empty")
36		}
37		return s.k8sClient.CreatePod(ctx, pod)
38	}
39	
40	func (s *service) DeletePod(ctx context.Context, name string) error {
41		if name == "" {
42			return fmt.Errorf("pod name cannot be empty")
43		}
44		return s.k8sClient.DeletePod(ctx, name)
45	}
46	
47	func (s *service) GetPod(ctx context.Context, name string) (*k8s.PodInfo, error) {
48		if name == "" {
49			return nil, fmt.Errorf("pod name cannot be empty")
50		}
51		return s.k8sClient.GetPod(ctx, name)
52	}
53	
54	func (s *service) ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error) {
55		return s.k8sClient.ListPods(ctx, labels)
56	}
57	
58	func (s *service) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
59		if name == "" {
60			return "", fmt.Errorf("pod name cannot be empty")
61		}
62		if tailLines <= 0 {
63			tailLines = 100
64		}
65		return s.k8sClient.GetPodLogs(ctx, name, tailLines)
66	}
