18	type client struct {
19		clientset *kubernetes.Clientset
20		namespace string
21	}
22	
23	// NewClient 创建 K8s 客户端
24	func NewClient(cfg config.K8sConfig) (Client, error) {
25		var k8sConfig *rest.Config
26		var err error
27	
28		if cfg.Kubeconfig != "" {
29			configPath := cfg.Kubeconfig
30			if !filepath.IsAbs(configPath) {
31				configPath = filepath.Join(filepath.Dir(""), configPath)
32			}
33			k8sConfig, err = clientcmd.BuildConfigFromFlags("", configPath)
34		} else {
35			k8sConfig, err = rest.InClusterConfig()
36		}
37		
38		if err != nil {
39			return nil, fmt.Errorf("failed to build k8s config: %w", err)
40		}
41	
42		clientset, err := kubernetes.NewForConfig(k8sConfig)
43		if err != nil {
44			return nil, fmt.Errorf("failed to create k8s clientset: %w", err)
45		}
46	
47		namespace := cfg.Namespace
48		if namespace == "" {
49			namespace = "default"
50		}
51	
52		return &client{
53			clientset: clientset,
54			namespace: namespace,
55		}, nil
56	}
57	
58	func (c *client) CreatePod(ctx context.Context, pod *PodSpec) error {
59		envVars := []corev1.EnvVar{}
60		for k, v := range pod.Env {
61			envVars = append(envVars, corev1.EnvVar{
62				Name:  k,
63				Value: v,
64			})
65		}
66	
67		container := corev1.Container{
68			Name:    pod.Name,
69			Image:   pod.Image,
70			Command: pod.Command,
71			Args:    pod.Args,
72			Env:     envVars,
73		}
74	
75		if pod.Resources != nil {
76			container.Resources = corev1.ResourceRequirements{
77				Requests: corev1.ResourceList{},
78				Limits:   corev1.ResourceList{},
79			}
80			if pod.Resources.CPURequest != "" {
81				container.Resources.Requests[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPURequest)
82			}
83			if pod.Resources.CPULimit != "" {
84				container.Resources.Limits[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPULimit)
85			}
86			if pod.Resources.MemoryRequest != "" {
87				container.Resources.Requests[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryRequest)
88			}
89			if pod.Resources.MemoryLimit != "" {
90				container.Resources.Limits[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryLimit)
91			}
92		}
93	
94		k8sPod := &corev1.Pod{
95			ObjectMeta: metav1.ObjectMeta{
96				Name:   pod.Name,
97				Labels: pod.Labels,
98			},
99			Spec: corev1.PodSpec{
100				Containers: []corev1.Container{container},
101			},
102		}
103	
104		_, err := c.clientset.CoreV1().Pods(c.namespace).Create(ctx, k8sPod, metav1.CreateOptions{})
105		return err
106	}
107	
108	func (c *client) DeletePod(ctx context.Context, name string) error {
109		return c.clientset.CoreV1().Pods(c.namespace).Delete(ctx, name, metav1.DeleteOptions{})
110	}
111	
112	func (c *client) GetPod(ctx context.Context, name string) (*PodInfo, error) {
113		pod, err := c.clientset.CoreV1().Pods(c.namespace).Get(ctx, name, metav1.GetOptions{})
114		if err != nil {
115			return nil, err
116		}
117	
118		image := ""
119		if len(pod.Spec.Containers) > 0 {
120			image = pod.Spec.Containers[0].Image
121		}
122	
123		return &PodInfo{
124			Name:      pod.Name,
125			Status:    string(pod.Status.Phase),
126			Image:     image,
127			CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
128			Labels:    pod.Labels,
129		}, nil
130	}
131	
132	func (c *client) ListPods(ctx context.Context, labelMap map[string]string) ([]PodInfo, error) {
133		selector := labels.SelectorFromSet(labelMap)
134		pods, err := c.clientset.CoreV1().Pods(c.namespace).List(ctx, metav1.ListOptions{
135			LabelSelector: selector.String(),
136		})
137		if err != nil {
138			return nil, err
139		}
140	
141		var podInfos []PodInfo
142		for _, pod := range pods.Items {
143			image := ""
144			if len(pod.Spec.Containers) > 0 {
145				image = pod.Spec.Containers[0].Image
146			}
147	
148			podInfos = append(podInfos, PodInfo{
149				Name:      pod.Name,
150				Status:    string(pod.Status.Phase),
151				Image:     image,
152				CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
153				Labels:    pod.Labels,
154			})
155		}
156	
157		return podInfos, nil
158	}
159	
160	func (c *client) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
161		req := c.clientset.CoreV1().Pods(c.namespace).GetLogs(name, &corev1.PodLogOptions{
162			TailLines: &tailLines,
163		})
164	
165		logs, err := req.Stream(ctx)
166		if err != nil {
167			return "", err
168		}
169		defer logs.Close()
170	
171		var logData []byte
172		buf := make([]byte, 1024)
173		for {
174			n, err := logs.Read(buf)
175			if n > 0 {
176				logData = append(logData, buf[:n]...)
177			}
178			if err != nil {
179				break
180			}
181		}
182	
183		return string(logData), nil
184	}
