64					Name:  "test-pod",
65					Image: "nginx:latest",
66				},
67				wantErr: false,
68			},
69			{
70				name: "empty name",
71				pod: &k8s.PodSpec{
72					Name:  "",
73					Image: "nginx:latest",
74				},
75				wantErr: true,
76			},
